import { cva } from 'class-variance-authority'
import { baseButtonVariants } from '@/components/ui/button/shared-button-variants'
import { brutalPress } from '@/lib/brutal-interaction-variants'

export const buttonVariants = cva(
    [
        'inline-flex items-center justify-center gap-2',
        'border-3 border-brutal',
        'rounded-brutal',
        'font-black tracking-wide',
        'transition-all duration-150',
        'focus:outline focus:outline-[3px] focus:outline-brutal-ring focus:outline-offset-2',
        'disabled:opacity-50 disabled:pointer-events-none',
        brutalPress,
    ],
    {
        variants: {
            ...baseButtonVariants.variants,
            effect: {
                none: '',
                glitch: 'glitch-button relative',
            },
            glitchSpeed: {
                slow: '[--glitch-duration:800ms]',
                medium: '[--glitch-duration:300ms]',
                fast: '[--glitch-duration:100ms]',
            },
            glitchDirection: {
                horizontal: 'glitch-horizontal',
                vertical: 'glitch-vertical',
                both: 'glitch-both',
            },
        },
        defaultVariants: {
            ...baseButtonVariants.defaultVariants,
            effect: 'none',
            glitchSpeed: 'medium',
            glitchDirection: 'horizontal',
        },
    }
)

import { computed, onBeforeUnmount, onMounted, shallowRef, toValue, watch, type MaybeRefOrGetter } from 'vue'
import { DEFAULT_AUTOPLAY_INTERVAL_MS, GLITCH_AUTOPLAY_ACTIVE_DURATION_MS, GLITCH_MIN_INTERVAL_MS } from '@/lib/defaults'
import { useReducedMotion } from '@/composables/useReducedMotion'

export type GlitchTrigger = 'hover' | 'click' | 'autoplay' | 'none'

export interface UseGlitchEffectOptions {
    trigger?: MaybeRefOrGetter<GlitchTrigger | undefined>
    interval?: MaybeRefOrGetter<number | undefined>
    disabled?: MaybeRefOrGetter<boolean | undefined>
}

export function useGlitchEffect(options: UseGlitchEffectOptions = {}) {
    const isActive = shallowRef(false)
    const prefersReducedMotion = useReducedMotion()
    const autoplayTimer = shallowRef<ReturnType<typeof setInterval> | null>(null)
    const autoplayStopTimer = shallowRef<ReturnType<typeof setTimeout> | null>(null)

    const trigger = computed(() => toValue(options.trigger) ?? 'hover')
    const isDisabled = computed(() => !!toValue(options.disabled))
    const isGlitching = computed(() => isActive.value && !prefersReducedMotion.value)

    function stopAutoplay() {
        if (autoplayTimer.value) {
            clearInterval(autoplayTimer.value)
            autoplayTimer.value = null
        }
        if (autoplayStopTimer.value) {
            clearTimeout(autoplayStopTimer.value)
            autoplayStopTimer.value = null
        }
    }

    function startAutoplay() {
        stopAutoplay()
        const interval = Math.max(Number(toValue(options.interval)) || DEFAULT_AUTOPLAY_INTERVAL_MS, GLITCH_MIN_INTERVAL_MS)
        autoplayTimer.value = setInterval(() => {
            if (prefersReducedMotion.value) return
            isActive.value = true
            if (autoplayStopTimer.value) {
                clearTimeout(autoplayStopTimer.value)
            }
            autoplayStopTimer.value = setTimeout(() => {
                isActive.value = false
            }, GLITCH_AUTOPLAY_ACTIVE_DURATION_MS)
        }, interval)
    }

    function onMouseEnter() {
        if (isDisabled.value) return
        if (trigger.value === 'hover') {
            isActive.value = true
        } else if (trigger.value === 'autoplay') {
            isActive.value = false
            stopAutoplay()
        }
    }

    function onMouseLeave() {
        if (isDisabled.value) return
        if (trigger.value === 'hover') {
            isActive.value = false
        } else if (trigger.value === 'autoplay') {
            startAutoplay()
        }
    }

    function onClick() {
        if (isDisabled.value) return
        if (trigger.value === 'click') {
            isActive.value = !isActive.value
        }
    }

    function play() {
        isActive.value = true
    }

    function stop() {
        isActive.value = false
    }

    onMounted(() => {
        if (trigger.value === 'autoplay') {
            startAutoplay()
        }
    })

    onBeforeUnmount(() => {
        stopAutoplay()
    })

    watch(trigger, (newTrigger, oldTrigger) => {
        if (oldTrigger === 'autoplay') {
            stopAutoplay()
            isActive.value = false
        }
        if (newTrigger === 'autoplay') {
            startAutoplay()
        }
    })

    watch(() => toValue(options.interval), () => {
        if (trigger.value === 'autoplay') {
            startAutoplay()
        }
    })

    watch(prefersReducedMotion, (prefersReduced) => {
        if (prefersReduced) {
            isActive.value = false
            if (trigger.value === 'autoplay') {
                stopAutoplay()
            }
        } else if (trigger.value === 'autoplay') {
            startAutoplay()
        }
    })

    return {
        isActive,
        isGlitching,
        prefersReducedMotion,
        onMouseEnter,
        onMouseLeave,
        onClick,
        play,
        stop,
        startAutoplay,
        stopAutoplay,
    }
}

import { type ComputedRef, type InjectionKey, type MaybeRef, computed, inject, provide, unref } from 'vue'
import { zhCN } from '@/locales/zh-CN'
import type { Locale } from '@/locales/types'

export const LOCALE_INJECTION_KEY: InjectionKey<MaybeRef<Locale>> = Symbol('brutx-ui-locale')
export const FALLBACK_LOCALE_INJECTION_KEY: InjectionKey<MaybeRef<Partial<Locale>>> = Symbol('brutx-ui-fallback-locale')

export type TranslateFunction = (path: string, params?: Record<string, string | number>) => string

export interface LocaleOptions {
    locale: MaybeRef<Locale>
    fallbackLocale?: MaybeRef<Partial<Locale>>
}

export function provideLocale(localeOrOptions: MaybeRef<Locale> | LocaleOptions): void {
    // 检查是否是 LocaleOptions 格式（包含 locale 属性）
    if (
        typeof localeOrOptions === 'object' &&
        localeOrOptions !== null &&
        'locale' in localeOrOptions
    ) {
        const options = localeOrOptions as LocaleOptions
        provide(LOCALE_INJECTION_KEY, options.locale)
        if (options.fallbackLocale) {
            provide(FALLBACK_LOCALE_INJECTION_KEY, options.fallbackLocale)
        }
    } else {
        // 直接传入 MaybeRef<Locale> 格式（向后兼容）
        provide(LOCALE_INJECTION_KEY, localeOrOptions as MaybeRef<Locale>)
    }
}

function resolveByPath(obj: unknown, path: string): string | undefined {
    const keys = path.split('.')
    let result: unknown = obj
    for (const key of keys) {
        if (typeof result !== 'object' || result === null) return undefined
        result = (result as Record<string, unknown>)[key]
    }
    return typeof result === 'string' ? result : undefined
}

function interpolate(template: string, params?: Record<string, string | number>): string {
    if (!params) return template
    return Object.entries(params).reduce(
        (str, [k, v]) => str.split(`{${k}}`).join(String(v)),
        template,
    )
}

export function useLocale(): { locale: ComputedRef<Locale>; t: TranslateFunction } {
    const injected = inject<MaybeRef<Locale> | undefined>(LOCALE_INJECTION_KEY, undefined)
    const injectedFallback = inject<MaybeRef<Partial<Locale>> | undefined>(FALLBACK_LOCALE_INJECTION_KEY, undefined)

    const locale = computed<Locale>(() => {
        const resolved = injected ? unref(injected) : undefined
        return resolved ?? zhCN
    })

    const fallbackLocale = computed<Partial<Locale>>(() => {
        return injectedFallback ? unref(injectedFallback) : {}
    })

    function t(path: string, params?: Record<string, string | number>): string {
        // 1. 尝试从用户 locale 查找
        const currentVal = resolveByPath(locale.value, path)
        if (currentVal !== undefined) return interpolate(currentVal, params)

        // 2. 尝试从自定义 fallback locale 查找
        if (fallbackLocale.value && Object.keys(fallbackLocale.value).length > 0) {
            const fallbackVal = resolveByPath(fallbackLocale.value, path)
            if (fallbackVal !== undefined) return interpolate(fallbackVal, params)
        }

        // 3. 尝试从默认 zhCN 查找
        const zhCNVal = resolveByPath(zhCN, path)
        if (zhCNVal !== undefined) return interpolate(zhCNVal, params)

        // 4. 返回 path 原文
        return path
    }

    return { locale, t }
}

import { ref, onMounted, onUnmounted, type Ref } from 'vue'
import { isClient } from '@/lib/env'

export function useReducedMotion(): Ref<boolean> {
    const prefersReduced = ref(false)
    let mediaQuery: MediaQueryList | null = null

    const onChange = (e: MediaQueryListEvent) => {
        prefersReduced.value = e.matches
    }

    onMounted(() => {
        if (isClient) {
            mediaQuery = window.matchMedia('(prefers-reduced-motion: reduce)')
            prefersReduced.value = mediaQuery.matches
            mediaQuery.addEventListener('change', onChange)
        }
    })

    onUnmounted(() => {
        mediaQuery?.removeEventListener('change', onChange)
    })

    return prefersReduced
}

